export type Cell = [number, number];

const coordKey = (x: number, y: number): string => `${x},${y}`;

export const nextGeneration = (cells: Cell[]): Cell[] => {
  const liveSet = new Set(cells.map(([x, y]) => coordKey(x, y)));
  const neighborCounts = new Map<string, { cell: Cell; count: number }>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const k = coordKey(nx, ny);
        const entry = neighborCounts.get(k);
        if (entry) {
          entry.count++;
        } else {
          neighborCounts.set(k, { cell: [nx, ny], count: 1 });
        }
      }
    }
  }

  const survives = (isAlive: boolean, count: number): boolean =>
    (isAlive && count === 2) || count === 3;

  const result: Cell[] = [];
  for (const [k, { cell, count }] of neighborCounts) {
    if (survives(liveSet.has(k), count)) {
      result.push(cell);
    }
  }

  return result;
};

